// Extract & validate the incoming WhatsApp message.
// Meta also sends status events (delivered, read) — we filter those out.

const body = $input.first().json.body;

if (!body?.entry?.[0]?.changes?.[0]?.value?.messages) {
  return []; // Not a message event — stop workflow
}

const value   = body.entry[0].changes[0].value;
const message = value.messages[0];
const contact = value.contacts?.[0];

const msgType = message.type;
let messageText   = '';
let buttonReplyId = null;

if (msgType === 'text') {
  messageText = message.text?.body || '';
} else if (msgType === 'interactive') {
  const iType = message.interactive?.type;
  if (iType === 'button_reply') {
    buttonReplyId = message.interactive.button_reply.id;
    messageText   = message.interactive.button_reply.title;
  } else if (iType === 'list_reply') {
    buttonReplyId = message.interactive.list_reply.id;
    messageText   = message.interactive.list_reply.title;
  }
} else if (msgType === 'button') {
  buttonReplyId = message.button?.payload;
  messageText   = message.button?.text || '';
}

return [{
  json: {
    from:          message.from,
    messageId:     message.id,
    messageType:   msgType,
    messageText,
    buttonReplyId,
    customerName:  contact?.profile?.name || 'there',
    phoneNumberId: value.metadata.phone_number_id,
    timestamp:     message.timestamp
  }
}];

// ═══════════════════════════════════════════════════════════════════════
// JERRYTECH Main Bot Brain — Part 4 (Final)
// Routes: Greeting · Booking · Status Check · Price Quotes
// ═══════════════════════════════════════════════════════════════════════

const msg = $('Extract Message Data').first().json;
const { from, messageText, buttonReplyId, customerName, phoneNumberId } = msg;

// ── Session ───────────────────────────────────────────────────────────────
const sessionRecords = $input.first().json.records || [];
const sessionRecord  = sessionRecords[0] || null;
const session = {
  step:        sessionRecord?.fields?.Step        || 'idle',
  tempDevice:  sessionRecord?.fields?.TempDevice  || '',
  tempProblem: sessionRecord?.fields?.TempProblem || '',
  tempDate:    sessionRecord?.fields?.TempDate    || ''
};

// ── WhatsApp message builders ─────────────────────────────────────────────
const textMsg = (text) => ({
  messaging_product: 'whatsapp', recipient_type: 'individual', to: from,
  type: 'text', text: { body: text }
});

const buttonMsg = (bodyText, footer, buttons) => ({
  messaging_product: 'whatsapp', recipient_type: 'individual', to: from,
  type: 'interactive',
  interactive: {
    type: 'button',
    body:   { text: bodyText },
    footer: { text: footer },
    action: { buttons: buttons.map(b => ({ type: 'reply', reply: { id: b.id, title: b.title } })) }
  }
});

const listMsg = (bodyText, btnLabel, rows) => ({
  messaging_product: 'whatsapp', recipient_type: 'individual', to: from,
  type: 'interactive',
  interactive: {
    type: 'list',
    body:   { text: bodyText },
    action: { button: btnLabel, sections: [{ title: 'Select one', rows }] }
  }
});

// Shared device list rows (reused in booking + quote flows)
const DEVICE_ROWS = [
  { id: 'device_iphone',  title: 'iPhone',      description: 'Apple iPhone' },
  { id: 'device_samsung', title: 'Samsung',     description: 'Galaxy series' },
  { id: 'device_tecno',   title: 'Tecno',       description: 'Spark / Camon / Pop' },
  { id: 'device_infinix', title: 'Infinix',     description: 'Hot / Note / Zero' },
  { id: 'device_other',   title: 'Other Brand', description: 'Huawei, Xiaomi, etc.' }
];

const DEVICE_MAP = {
  device_iphone: 'iPhone', device_samsung: 'Samsung',
  device_tecno: 'Tecno',   device_infinix: 'Infinix', device_other: 'Other'
};

// ── Price table — edit amounts to match your rates (currency: GHS) ────────
const PRICES = {
  iPhone:  { repair_screen: [350,700], repair_battery: [150,220], repair_charging: [100,180], repair_camera: [200,400], repair_water: [150,400], repair_software: [80,150],  repair_speaker: [120,200] },
  Samsung: { repair_screen: [250,550], repair_battery: [100,180], repair_charging: [80,150],  repair_camera: [150,300], repair_water: [120,350], repair_software: [70,130],  repair_speaker: [100,180] },
  Tecno:   { repair_screen: [100,250], repair_battery: [60,120],  repair_charging: [50,100],  repair_camera: [80,170],  repair_water: [80,220],  repair_software: [50,100],  repair_speaker: [60,120]  },
  Infinix: { repair_screen: [100,250], repair_battery: [60,120],  repair_charging: [50,100],  repair_camera: [80,170],  repair_water: [80,220],  repair_software: [50,100],  repair_speaker: [60,120]  },
  Other:   { repair_screen: [80,300],  repair_battery: [60,150],  repair_charging: [50,120],  repair_camera: [80,200],  repair_water: [80,250],  repair_software: [50,110],  repair_speaker: [60,140]  }
};

const REPAIR_LABELS = {
  repair_screen:   'Screen Replacement',
  repair_battery:  'Battery Replacement',
  repair_charging: 'Charging Port Repair',
  repair_camera:   'Camera Repair',
  repair_water:    'Water Damage Assessment',
  repair_software: 'Software Fix',
  repair_speaker:  'Speaker / Mic Repair'
};

// ── Routing vars ──────────────────────────────────────────────────────────
let whatsappPayload;
let newSessionFields    = {};
let createBooking       = false;
let bookingBody         = null;
let performStatusLookup = false;
let statusLookupType    = '';
let statusLookupFilter  = '';

const step  = session.step;
const btnId = buttonReplyId;

// ════════════════════════════════════════════════════════════════════════
// BOOKING FLOW
// ════════════════════════════════════════════════════════════════════════

if (btnId === 'book_appointment') {
  newSessionFields = { Phone: from, Step: 'booking_device', TempDevice: '', TempProblem: '', TempDate: '' };
  whatsappPayload  = listMsg('📱 What type of device needs repair?', 'Select Device', DEVICE_ROWS);

} else if (step === 'booking_device') {
  const device = (btnId && DEVICE_MAP[btnId]) ? DEVICE_MAP[btnId] : messageText;
  newSessionFields = { Phone: from, Step: 'booking_problem', TempDevice: device };
  whatsappPayload  = textMsg(`Got it — *${device}* 👍\n\nPlease describe the problem with your device:\n_(e.g. cracked screen, won't charge, water damage, camera issue)_`);

} else if (step === 'booking_problem') {
  newSessionFields = { Phone: from, Step: 'booking_date', TempProblem: messageText };
  whatsappPayload  = textMsg(`Noted! 📝\n\nWhat date would you prefer to bring in your device?\n_Reply with a date, e.g: *28 Feb 2026*_`);

} else if (step === 'booking_date') {
  newSessionFields = { Phone: from, Step: 'booking_time', TempDate: messageText };
  whatsappPayload  = buttonMsg(
    `What time works for you on *${messageText}*? 🕐`,
    'Open Mon–Sat, 9am–6pm',
    [
      { id: 'time_morning',   title: 'Morning (9am-12pm)' },
      { id: 'time_afternoon', title: 'Afternoon (12-4pm)' },
      { id: 'time_evening',   title: 'Evening (4-6pm)'    }
    ]
  );

} else if (step === 'booking_time') {
  const timeMap  = { time_morning: 'Morning (9am–12pm)', time_afternoon: 'Afternoon (12–4pm)', time_evening: 'Evening (4–6pm)' };
  const timeSlot = (btnId && timeMap[btnId]) ? timeMap[btnId] : messageText;
  const ref      = 'JT-' + Date.now().toString().slice(-6);
  newSessionFields = { Phone: from, Step: 'idle', TempDevice: '', TempProblem: '', TempDate: '' };
  createBooking    = true;
  bookingBody      = {
    records: [{ fields: {
      Reference: ref, CustomerName: customerName, Phone: from,
      Device: session.tempDevice, Problem: session.tempProblem,
      PreferredDate: session.tempDate, PreferredTime: timeSlot, Status: 'Pending'
    }}]
  };
  whatsappPayload = textMsg(
    `✅ *Booking Confirmed!*\n\n` +
    `📋 *Ref:* ${ref}\n` +
    `📱 *Device:* ${session.tempDevice}\n` +
    `🔧 *Problem:* ${session.tempProblem}\n` +
    `📅 *Date:* ${session.tempDate}\n` +
    `🕐 *Time:* ${timeSlot}\n\n` +
    `We'll see you then! To reschedule, just send us a message.\n— *JERRYTECH Phone Repairs* 🛠️`
  );

// ════════════════════════════════════════════════════════════════════════
// STATUS CHECK FLOW
// ════════════════════════════════════════════════════════════════════════

} else if (btnId === 'check_status') {
  newSessionFields = { Phone: from, Step: 'status_ref_lookup' };
  whatsappPayload  = textMsg(
    `🔍 Please enter your booking reference number to check your repair status.\n\n_Example: *JT-483921*_\n\nNo reference? Reply *PHONE* to search by your WhatsApp number.`
  );

} else if (step === 'status_ref_lookup') {
  const isPhoneLookup = messageText.trim().toUpperCase() === 'PHONE';
  const lookupValue   = isPhoneLookup ? from : messageText.trim().toUpperCase();
  newSessionFields    = { Phone: from, Step: 'idle' };
  performStatusLookup = true;
  statusLookupType    = isPhoneLookup ? 'phone' : 'reference';
  statusLookupFilter  = isPhoneLookup
    ? encodeURIComponent(`({Phone}='${from}')`)
    : encodeURIComponent(`({Reference}='${lookupValue}')`);
  whatsappPayload = null;

// ════════════════════════════════════════════════════════════════════════
// PRICE QUOTE FLOW
// ════════════════════════════════════════════════════════════════════════

} else if (btnId === 'get_quote') {
  // Step 1 — Ask for device type
  newSessionFields = { Phone: from, Step: 'quote_device', TempDevice: '' };
  whatsappPayload  = listMsg(
    '💰 Get an instant price estimate!\n\nWhat type of device do you have?',
    'Select Device',
    DEVICE_ROWS
  );

} else if (step === 'quote_device') {
  // Step 2 — Got device, ask for repair type
  const device = (btnId && DEVICE_MAP[btnId]) ? DEVICE_MAP[btnId] : messageText;
  newSessionFields = { Phone: from, Step: 'quote_repair', TempDevice: device };
  whatsappPayload  = listMsg(
    `Great — *${device}* 📱\n\nWhat type of repair do you need a quote for?`,
    'Select Repair',
    [
      { id: 'repair_screen',   title: 'Screen',        description: 'Cracked / broken screen'      },
      { id: 'repair_battery',  title: 'Battery',       description: 'Battery replacement'           },
      { id: 'repair_charging', title: 'Charging Port', description: "Won't charge / loose port"     },
      { id: 'repair_camera',   title: 'Camera',        description: 'Camera not working'             },
      { id: 'repair_water',    title: 'Water Damage',  description: 'Liquid damage assessment'      },
      { id: 'repair_software', title: 'Software Fix',  description: 'Virus, slow, won\'t boot'      },
      { id: 'repair_speaker',  title: 'Speaker / Mic', description: 'Audio issue'                   }
    ]
  );

} else if (step === 'quote_repair') {
  // Step 3 — Look up price and return estimate with Book Now button
  const repairId   = btnId || 'repair_screen';
  const device     = session.tempDevice || 'Other';
  const priceRange = (PRICES[device] || PRICES['Other'])[repairId] || [80, 300];
  const label      = REPAIR_LABELS[repairId] || 'Repair';

  newSessionFields = { Phone: from, Step: 'idle' };
  whatsappPayload  = buttonMsg(
    `💰 *JERRYTECH Price Estimate*\n\n` +
    `📱 *Device:* ${device}\n` +
    `🔧 *Repair:* ${label}\n` +
    `💵 *Estimate:* GHS ${priceRange[0]} – GHS ${priceRange[1]}\n\n` +
    `_Final price may vary by model & parts availability.\nBring in your device for a free physical assessment!_`,
    'Ready to fix it? Tap below!',
    [
      { id: 'book_appointment', title: 'Book Appointment'  },
      { id: 'get_quote',        title: 'Get Another Quote' }
    ]
  );

// ════════════════════════════════════════════════════════════════════════
// DEFAULT — Show main menu
// ════════════════════════════════════════════════════════════════════════

} else {
  newSessionFields = { Phone: from, Step: 'idle' };
  whatsappPayload  = buttonMsg(
    `Hi ${customerName}! 👋 Welcome to *JERRYTECH Phone Repairs*. 📱\n\nWe fix phones fast & affordably.\nHow can we help you today?`,
    'Tap a button below to get started',
    [
      { id: 'book_appointment', title: 'Book Appointment'   },
      { id: 'check_status',     title: 'Check Repair Status' },
      { id: 'get_quote',        title: 'Get a Quote'        }
    ]
  );
}

const sessionBody = {
  performUpsert: { fieldsToMergeOn: ['Phone'] },
  records: [{ fields: newSessionFields }]
};

return [{ json: {
  phoneNumberId, whatsappPayload, createBooking, sessionBody, bookingBody,
  performStatusLookup, statusLookupType, statusLookupFilter
} }];

// Build the repair status reply from the Airtable Bookings query result.

const records  = $input.first().json.records || [];
const brain    = $('Main Bot Brain').first().json;
const from     = $('Extract Message Data').first().json.from;
const { phoneNumberId, statusLookupType } = brain;

let responseText;

if (records.length === 0) {
  const hint = statusLookupType === 'phone'
    ? 'your WhatsApp number'
    : 'that reference number';
  responseText =
    `❌ We couldn't find any bookings linked to ${hint}.\n\n` +
    `Please double-check your reference (e.g. *JT-483921*) and try again, ` +
    `or message us directly and we'll look it up for you.\n— *JERRYTECH Phone Repairs* 🛠️`;
} else {
  // If multiple bookings, show the most recent (first returned)
  const b = records[0].fields;
  const statusEmoji = {
    'Pending':     '⏳',
    'Confirmed':   '✅',
    'In Progress': '🔧',
    'Completed':   '🎉',
    'Cancelled':   '❌'
  }[b.Status] || '📋';

  responseText =
    `${statusEmoji} *Repair Status Update*\n\n` +
    `📋 *Ref:*     ${b.Reference    || 'N/A'}\n` +
    `📱 *Device:*  ${b.Device       || 'N/A'}\n` +
    `🔧 *Problem:* ${b.Problem      || 'N/A'}\n` +
    `📅 *Date:*    ${b.PreferredDate || 'N/A'}\n` +
    `🕐 *Time:*    ${b.PreferredTime || 'N/A'}\n` +
    `📊 *Status:*  *${b.Status}*\n\n` +
    `Questions? Just reply to this message and we'll assist you.\n— *JERRYTECH Phone Repairs* 🛠️`;
}

return [{
  json: {
    phoneNumberId,
    whatsappPayload: {
      messaging_product: 'whatsapp',
      recipient_type:    'individual',
      to:                from,
      type:              'text',
      text:              { body: responseText }
    }
  }
}];
